mapper.select:
select
a.zid as zid, a.zcode as username, a.zpassword as password, a.zname as xm, a.zrole as role
from t_operator a where zcode=#{username} and zpassword=#{password}

        select
        *
        from t_media a




					and a.zname like #{znameLike} 



					and a.zlinkman like #{zlinkmanLike} 



					and a.ztel like #{ztelLike} 


					and a.zrole = #{param.zrole} 



		order by to_number(zcode)

        select 
        *
        from t_operator a

			a.zcode = #{zcode}
			and a.zid  <>  #{zid}

mapper.update:
update t_media
zcode=#{zcode,jdbcType=VARCHAR}, zname=#{zname,jdbcType=VARCHAR}, zaddress=#{zaddress,jdbcType=VARCHAR}, zlinkman=#{zlinkman,jdbcType=VARCHAR}, ztel=#{ztel,jdbcType=VARCHAR}, zpassword=#{zpassword,jdbcType=VARCHAR}, zunitcode=#{zunitcode,jdbcType=VARCHAR}, zsortindex=#{zsortindex,jdbcType=NUMERIC},
where zid=#{zid,jdbcType=VARCHAR}
